/**
 * @author Alex-Vasile
 */
public class KarnsSylex extends CardImpl {
    public KarnsSylex(UUID ownerId, CardSetInfo setInfo) {
        super(ownerId, setInfo, new CardType[]{CardType.ARTIFACT}, "{3}");
        this.supertype.add(SuperType.LEGENDARY);
        this.addAbility(new EntersBattlefieldTappedAbility());
        this.addAbility(new CantPayLifeOrSacrificeAbility(true, null));
        Ability ability = new ActivateAsSorceryActivatedAbility(new KarnsSylexDestroyEffect(), new ManaCostsImpl<>("{X}"));
        ability.addCost(new TapSourceCost());
        ability.addCost(new ExileSourceCost());
        this.addAbility(ability);
    }
    private KarnsSylex(final KarnsSylex card) {
        super(card);
    }
    @Override
    public KarnsSylex copy() {
        return new KarnsSylex(this);
    }
}
class KarnsSylexDestroyEffect extends OneShotEffect {
    KarnsSylexDestroyEffect() {
        super(Outcome.DestroyPermanent);
        staticText = "Destroy each nonland permanent with mana value X or less.";
    }
    private KarnsSylexDestroyEffect(final KarnsSylexDestroyEffect effect) {
        super(effect);
    }
    public KarnsSylexDestroyEffect copy() {
        return new KarnsSylexDestroyEffect(this);
    }
    @Override
    public boolean apply(Game game, Ability source) {
        FilterNonlandPermanent filter = new FilterNonlandPermanent();
        filter.add(new ManaValuePredicate(ComparisonType.FEWER_THAN, CardUtil.getSourceCostsTag(game, source, "X", 0) + 1));
        boolean destroyed = false;
        for (Permanent permanent : game.getBattlefield().getActivePermanents(filter, source.getControllerId(), game)) {
            destroyed |= permanent.destroy(source, game);
        }
        return destroyed;

/**
 * @author TheElk801
 */
public final class KarnTheGreatCreator extends CardImpl {
    private static final FilterPermanent filter
            = new FilterArtifactPermanent("noncreature artifact");
    static {
        filter.add(Predicates.not(CardType.CREATURE.getPredicate()));
    }
    public KarnTheGreatCreator(UUID ownerId, CardSetInfo setInfo) {
        super(ownerId, setInfo, new CardType[]{CardType.PLANESWALKER}, "{4}");
        this.supertype.add(SuperType.LEGENDARY);
        this.subtype.add(SubType.KARN);
        this.setStartingLoyalty(5);
        this.addAbility(new SimpleStaticAbility(new KarnTheGreatCreatorCantActivateEffect()));
        Ability ability = new LoyaltyAbility(new KarnTheGreatCreatorAnimateEffect(), 1);
        ability.addTarget(new TargetPermanent(0, 1, filter, false));
        this.addAbility(ability);
        this.addAbility(new LoyaltyAbility(new WishEffect(
                StaticFilters.FILTER_CARD_ARTIFACT, true
        ), -2).addHint(OpenSideboardHint.instance));
    }
    private KarnTheGreatCreator(final KarnTheGreatCreator card) {
        super(card);
    }
    @Override
    public KarnTheGreatCreator copy() {
        return new KarnTheGreatCreator(this);
    }
}
class KarnTheGreatCreatorCantActivateEffect extends RestrictionEffect {
    KarnTheGreatCreatorCantActivateEffect() {
        super(Duration.WhileOnBattlefield);
        staticText = "Activated abilities of artifacts your opponents control can't be activated";
    }
    private KarnTheGreatCreatorCantActivateEffect(final KarnTheGreatCreatorCantActivateEffect effect) {
        super(effect);
    }
    @Override
    public boolean applies(Permanent permanent, Ability source, Game game) {
        return permanent.isArtifact(game) && game.getOpponents(source.getControllerId()).contains(permanent.getControllerId());
    }

/**
 * @author TheElk801
 */
public final class NaktamunLorespinner extends PrepareCard {
    public NaktamunLorespinner(UUID ownerId, CardSetInfo setInfo) {
        super(ownerId, setInfo, new CardType[]{CardType.CREATURE}, "{2}{R}", "Wheel of Fortune", new CardType[]{CardType.SORCERY}, "{2}{R}");
        this.subtype.add(SubType.JACKAL);
        this.subtype.add(SubType.WIZARD);
        this.power = new MageInt(3);
        this.toughness = new MageInt(3);
        this.addAbility(new BeginningOfUpkeepTriggeredAbility(new BecomePreparedSourceEffect())
                .withInterveningIf(NaktamunLorespinnerCondition.instance));
        this.getSpellCard().getSpellAbility().addEffect(new DiscardHandAllEffect());
        this.getSpellCard().getSpellAbility().addEffect(new DrawCardAllEffect(7).setText(", then draws seven cards"));
    }
    private NaktamunLorespinner(final NaktamunLorespinner card) {
        super(card);
    }
    @Override
    public NaktamunLorespinner copy() {
        return new NaktamunLorespinner(this);
    }
}
enum NaktamunLorespinnerCondition implements Condition {
    instance;
    @Override
    public boolean apply(Game game, Ability source) {
        return game
                .getState()
                .getPlayersInRange(source.getControllerId(), game)
                .stream()
                .map(game::getPlayer)
                .filter(Objects::nonNull)
                .map(Player::getHand)
                .mapToInt(Set::size)
                .anyMatch(x -> x <= 1);
    }
    @Override
    public String toString() {
        return "a player has one or fewer cards in hand";
    }
}
